t.script:
(function () {
    'use strict';

    /* ----------------------------------------------------------------
     * JSON-RPC helper
     * type='jsonrpc' routes in Odoo 19 do NOT require a CSRF token —
     * they are protected by the session cookie + Content-Type check.
     * ---------------------------------------------------------------- */
    function jsonRpc(url, params) {
        return fetch(url, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                jsonrpc: '2.0',
                method:  'call',
                id:      Date.now(),
                params:  params || {},
            }),
        })
        .then(function (r) { return r.json(); })
        .then(function (r) {
            if (r.error) {
                /* Surface a readable message from JSON-RPC error */
                var msg = (r.error.data && r.error.data.message)
                        || r.error.message
                        || 'Server error';
                return { error: msg };
            }
            return r.result;
        });
    }

    /* ----------------------------------------------------------------
     * Elapsed formatter — always receives UTC epoch ms
     * ---------------------------------------------------------------- */
    function formatElapsed(startMs) {
        var diff = Math.max(0, Math.floor((Date.now() - startMs) / 1000));
        var h = Math.floor(diff / 3600);
        var m = Math.floor((diff % 3600) / 60);
        var s = diff % 60;
        return [h, m, s].map(function (v) {
            return String(v).padStart(2, '0');
        }).join(':');
    }

    /* ---- Live timer tick ---- */
    var timerInterval = null;

    function startElapsedTick(startMs) {
        var el = document.getElementById('elapsed_display');
        if (!el) return;
        el.textContent = formatElapsed(startMs);
        clearInterval(timerInterval);
        timerInterval = setInterval(function () {
            el.textContent = formatElapsed(startMs);
        }, 1000);
    }

    /* ---- Start timer ---- */
    var btnStart = document.getElementById('btn_start_timer');
    if (btnStart) {
        btnStart.addEventListener('click', function () {
            var taskId = btnStart.getAttribute('data-task-id');
            btnStart.disabled = true;
            jsonRpc('/my/tasks/' + taskId + '/timer/start', {})
                .then(function (res) {
                    if (res && res.success) {
                        window.location.reload();
                    } else {
                        alert((res && res.error) || 'Could not start timer.');
                        btnStart.disabled = false;
                    }
                })
                .catch(function () {
                    alert('An error occurred. Please try again.');
                    btnStart.disabled = false;
                });
        });
    }

    /* ---- Auto-start tick if timer already running ---- */
    var btnStop = document.getElementById('btn_stop_timer');
    if (btnStop) {
        /* epoch ms passed from server — always UTC, always correct */
        var startMs = parseInt(btnStop.getAttribute('data-timer-start-ms'), 10);

        /* Show "Started at" in the user's local clock time */
        var startEl = document.getElementById('timer_start_display');
        if (startEl && startMs) {
            startEl.textContent = new Date(startMs).toLocaleTimeString();
        }

        /* Begin ticking */
        if (startMs) {
            startElapsedTick(startMs);
        }

        /* ---- Stop timer ---- */
        btnStop.addEventListener('click', function () {
            var taskId      = btnStop.getAttribute('data-task-id');
            var descEl      = document.getElementById('timer_stop_description');
            var description = descEl ? descEl.value : '';
            btnStop.disabled = true;
            clearInterval(timerInterval);

            jsonRpc('/my/tasks/' + taskId + '/timer/stop', { description: description })
                .then(function (res) {
                    if (res && res.success) {
                        window.location.reload();
                    } else {
                        alert((res && res.error) || 'Could not stop timer.');
                        btnStop.disabled = false;
                        startElapsedTick(startMs);
                    }
                })
                .catch(function () {
                    alert('An error occurred. Please try again.');
                    btnStop.disabled = false;
                    startElapsedTick(startMs);
                });
        });
    }

    /* ---- Manual timesheet submit ---- */
    var btnManual = document.getElementById('btn_manual_submit');
    if (btnManual) {
        var dateInput = document.getElementById('manual_ts_date');
        if (dateInput && !dateInput.value) {
            dateInput.value = new Date().toISOString().slice(0, 10);
        }

        btnManual.addEventListener('click', function () {
            var taskId  = btnManual.getAttribute('data-task-id');
            var desc    = document.getElementById('manual_ts_desc').value;
            var hours   = document.getElementById('manual_ts_hours').value;
            var date    = document.getElementById('manual_ts_date').value;
            var alertEl = document.getElementById('manual_ts_alert');

            function showAlert(msg, type) {
                alertEl.textContent = msg;
                alertEl.className = 'alert alert-' + type;
            }

            if (!desc.trim()) {
                return showAlert('Please enter a description.', 'warning');
            }
            if (!hours || parseFloat(hours) <= 0) {
                return showAlert('Please enter a valid number of hours.', 'warning');
            }

            btnManual.disabled = true;
            jsonRpc('/my/tasks/' + taskId + '/timesheet/submit', {
                description: desc,
                hours:       parseFloat(hours),
                date:        date || null,
            })
            .then(function (res) {
                if (res && res.success) {
                    showAlert('Timesheet submitted — awaiting manager approval.', 'success');
                    document.getElementById('manual_ts_desc').value  = '';
                    document.getElementById('manual_ts_hours').value = '';
                    setTimeout(function () { window.location.reload(); }, 1500);
                } else {
                    showAlert((res && res.error) || 'Submission failed.', 'danger');
                    btnManual.disabled = false;
                }
            })
            .catch(function () {
                showAlert('An error occurred. Please try again.', 'danger');
                btnManual.disabled = false;
            });
        });
    }

}());
